import{_ as s,o as i,c as t,a6 as l,eL as e,eM as r,eN as n,eO as o,eP as p}from"./chunks/framework.UYVGz2W_.js";const b=JSON.parse('{"title":"ボット","description":"","frontmatter":{},"headers":[],"relativePath":"ja/bots/index.md","filePath":"ja/bots/index.md"}'),h={name:"ja/bots/index.md"};function g(d,a,c,_,k,m){return i(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="ボット" tabindex="-1">ボット <a class="header-anchor" href="#ボット" aria-label="Permalink to “ボット”">​</a></h1><p>Kitsuのボットは、自動化されたタスクを実行できる非物理的なユーザーです。これにより、実際のユーザーとしてログインすることなく、スクリプトを実行したり、KitsuのAPIとやりとりしたりすることができます。</p><p>::: ヒント ボットはアクティブユーザーとしてカウントされないため、契約プランに関係なく、必要な数だけ作成することができます。 :::B</p><h2 id="ボットを使用する理由" tabindex="-1">ボットを使用する理由 <a class="header-anchor" href="#ボットを使用する理由" aria-label="Permalink to “ボットを使用する理由”">​</a></h2><p>ボットの主な用途は、Gazu や Kitsu API を使用できるその他のアプリケーションでのスクリプト作成です。ボットは、実ユーザーに限定されているものを除き、ほぼすべての API ルートにアクセスできます。</p><p>主な利点：**</p><ul><li>自動化されたタスクやスクリプトの実行</li><li>Kitsu API とのやりとり</li><li>トークンを使用することでシステムセキュリティを維持</li></ul><h2 id="ボットの作成方法" tabindex="-1">ボットの作成方法 <a class="header-anchor" href="#ボットの作成方法" aria-label="Permalink to “ボットの作成方法”">​</a></h2><p>::: 警告 初めてボットを作成すると、<strong>JWTトークン</strong>が発行されます。このトークンはAPIへの接続に不可欠ですので、安全に保管してください。 :::</p><ol><li><strong>ボットページに移動します。</strong>メインメニューの管理セクションで、ボットページに移動します。</li></ol><p><img src="'+e+'" alt="メインメニューボット"></p><ol start="2"><li><strong>新しいボットを追加：</strong> [新しいボット] ボタンをクリックします。 <img src="'+r+'" alt="新しいボット"> ポップアップウィンドウが表示され、ボットの詳細を入力できます。</li></ol><ul><li><strong>名前：</strong> ボットに名前を付けます。</li><li><strong>有効期限：</strong> 必要に応じて有効期限を設定します。</li><li><strong>部署：</strong> ボットを特定の部署にリンクします。</li><li><strong>役割：</strong> ボットの役割を定義します。</li><li><strong>アクティブ：</strong> ボットをアクティブにするか非アクティブにするかを選択します。</li></ul><p><img src="'+n+'" alt="ボットの作成例"></p><ol start="3"><li><strong>ボットの作成：</strong> 詳細を入力し、<strong>ユーザー作成</strong>をクリックします。</li></ol><p><img src="'+o+'" alt="ボット作成例"></p><p>新しいポップアップにボットの<strong>APIトークン</strong>が表示されます。</p><p><img src="'+p+`" alt="ボットトークン例"></p><h2 id="ボットの管理" tabindex="-1">ボットの管理 <a class="header-anchor" href="#ボットの管理" aria-label="Permalink to “ボットの管理”">​</a></h2><p>ボットページでは、他のユーザーと同様に、ボットを管理することができます。例えば、以下の操作が可能です。</p><ul><li>役割の割り当て</li><li>有効期限の設定</li><li>ステータスの変更（アクティブまたは非アクティブ</li></ul><h2 id="ボットの使用例" tabindex="-1">ボットの使用例 <a class="header-anchor" href="#ボットの使用例" aria-label="Permalink to “ボットの使用例”">​</a></h2><p>以下は、ボットを使用してプロジェクト<strong>MyProduction</strong>全体を取得するためのスクリプトの例です。</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> gazu</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gazu.set_host(「yourkitsu.cg-wire.com/api/」)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gazu.set_token(「my_jwt_token」)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p = gazu.project.get_project_by_name(「MyProduction」)</span></span></code></pre></div><p>このスクリプトは、実際のユーザーのログイン認証情報を使用せずに、ボットを使用してKitsu APIとやりとりする方法を示しています。必要に応じて、コメントを公開するボットがある場合は、そのボットに実際のユーザーと同じ権限を付与して、権限を考慮することができます。</p><h2 id="セキュリティに関する考慮事項" tabindex="-1">セキュリティに関する考慮事項 <a class="header-anchor" href="#セキュリティに関する考慮事項" aria-label="Permalink to “セキュリティに関する考慮事項”">​</a></h2><p>ボットのトークンが侵害された場合は、新しいトークンを再生成することで、古いトークンを無効にすることができ、システムのセキュリティを確保することができます。</p>`,27)])])}const P=s(h,[["render",g]]);export{b as __pageData,P as default};
